// Script Continued Below
function onLoad() {
	// DFCT0011799
	g_form.setDisplay('u_organizational_privacy',g_scratchpad.organizational_privacy_on);


	// STRY0117523 
	g_form.setDisplay('u_schedule_override',g_scratchpad.enable_office_schedule_override);
	// STRY0127037
	if(g_scratchpad.enable_office_schedule_override){
		if(!g_scratchpad.canReadSchedule){
			g_form.showFieldMsg('u_schedule_override',getMessage('Tasker - This feature requires ServiceNow Administrative permissions. If disabled, please contact your Administrator.'), 'warning');
		}	
		g_form.showFieldMsg('u_schedule_override',getMessage('Tasker - Tasks and Templates in this Office will set the suspense date to follow the selected schedule. Otherwise, it will follow system settings.'), 'info');
	}

	//RJ -ET - Story 1

	// STRY0074671 - hide members
	if(g_form.getValue('u_external_flag') == 'true'){
		g_form.hideRelatedList('x_153465_discovert_discover_office_members');
	}

	//STRY0059849 - OU Roles - OU Hierarchy Administrator
	if(g_form.getValue('u_ou_hierarchy_administrators') == ''){
		g_form.showFieldMsg('u_ou_hierarchy_administrators',getMessage('No OU Hierarchy Administrators in this OU.  The OU Hierarchy Administrator(s) ({0}) from OU ({1}) are responsible for maintaining this OU.').replace('{0}',g_scratchpad.OUHA_responsible.Administrators.displayValue).replace('{1}',g_scratchpad.OUHA_responsible.OU.displayValue), 'info');
	}else{
		g_form.hideFieldMsg('u_ou_hierarchy_administrators');
	}	
}
